import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, Cell, PieChart, Pie 
} from 'recharts';
import { Calendar, Filter, Download, DollarSign, Users, TrendingUp, ShoppingBag, PieChart as PieIcon, ArrowLeft, ChevronRight, FileText } from 'lucide-react';
import { DailyEntry, Ingredient, ActivityLog } from '../types';

interface ReportingProps {
  entries: DailyEntry[];
  logs: ActivityLog[];
  ingredients: Ingredient[];
}

type TimeFrame = 'week' | 'month' | 'quarter' | 'year' | 'custom';

export const Reporting: React.FC<ReportingProps> = ({ entries, logs, ingredients }) => {
  const [timeFrame, setTimeFrame] = useState<TimeFrame>('month');
  const [customStartDate, setCustomStartDate] = useState('');
  const [customEndDate, setCustomEndDate] = useState('');
  const [expandedVendor, setExpandedVendor] = useState<string | null>(null);

  // --- 1. Date Filtering Logic ---
  const { startDate, endDate, label } = useMemo(() => {
    const end = new Date();
    let start = new Date();
    let lbl = '';

    if (timeFrame === 'custom') {
      return {
        startDate: customStartDate ? new Date(customStartDate) : new Date(0),
        endDate: customEndDate ? new Date(customEndDate) : new Date(),
        label: `${customStartDate} to ${customEndDate}`
      };
    }

    end.setHours(23, 59, 59, 999);
    start.setHours(0, 0, 0, 0);

    switch (timeFrame) {
      case 'week':
        start.setDate(end.getDate() - 7);
        lbl = 'Last 7 Days';
        break;
      case 'month':
        start.setDate(1);
        lbl = 'This Month';
        break;
      case 'quarter':
        start.setMonth(Math.floor(end.getMonth() / 3) * 3);
        start.setDate(1);
        lbl = 'This Quarter';
        break;
      case 'year':
        start.setMonth(0, 1);
        lbl = 'This Year';
        break;
    }

    return { startDate: start, endDate: end, label: lbl };
  }, [timeFrame, customStartDate, customEndDate]);

  // --- 2. Filter Data ---
  const filteredEntries = useMemo(() => {
    return entries.filter(e => {
      const d = new Date(e.date);
      return d >= startDate && d <= endDate;
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [entries, startDate, endDate]);

  const filteredPurchases = useMemo(() => {
    return logs.filter(l => {
        const d = new Date(l.timestamp);
        return l.action === 'UPDATE_STOCK' && 
               l.metadata?.type === 'add' && 
               l.metadata?.quantity > 0 &&
               d >= startDate && 
               d <= endDate;
    });
  }, [logs, startDate, endDate]);

  // --- 3. Calculate Consumption Metrics ---
  const consumptionStats = useMemo(() => {
    const totalCost = filteredEntries.reduce((sum, e) => sum + e.totalCost, 0);
    const totalParticipants = filteredEntries.reduce((sum, e) => sum + e.participantCount, 0);
    const daysCount = filteredEntries.length || 1;

    return {
        totalCost,
        totalParticipants,
        avgCostPerHead: totalParticipants > 0 ? totalCost / totalParticipants : 0,
        avgDailyCost: totalCost / daysCount,
        avgDailyParticipants: Math.round(totalParticipants / daysCount)
    };
  }, [filteredEntries]);

  // --- 4. Calculate Vendor/Purchase Metrics ---
  const purchaseStats = useMemo(() => {
    let totalPurchaseEst = 0;
    const vendorMap: Record<string, number> = {};
    const vendorTxs: Record<string, any[]> = {};

    filteredPurchases.forEach(log => {
        const ing = ingredients.find(i => i.id === log.metadata.ingredientId);
        const cost = (log.metadata.quantity || 0) * (ing?.unitPrice || 0);
        const supplier = log.metadata.supplier || ing?.supplierName || 'Unassigned / Local Market';

        totalPurchaseEst += cost;
        vendorMap[supplier] = (vendorMap[supplier] || 0) + cost;

        if (!vendorTxs[supplier]) vendorTxs[supplier] = [];
        vendorTxs[supplier].push({
          id: log.id,
          date: log.timestamp,
          itemName: ing?.name || 'Unknown Item',
          unit: ing?.unit || 'units',
          quantity: log.metadata.quantity,
          unitPrice: ing?.unitPrice || 0,
          total: cost
        });
    });

    const vendorData = Object.entries(vendorMap)
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value);

    // Sort transactions within each vendor by date desc
    Object.keys(vendorTxs).forEach(key => {
      vendorTxs[key].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    });

    return {
        totalPurchaseEst,
        vendorData,
        vendorTxs
    };
  }, [filteredPurchases, ingredients]);

  // --- 5. Chart Data Prep ---
  const dailyTrendData = useMemo(() => {
    return filteredEntries.map(e => ({
        date: new Date(e.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' }),
        fullDate: e.date,
        Cost: e.totalCost,
        Participants: e.participantCount,
        PerHead: e.participantCount ? Number((e.totalCost / e.participantCount).toFixed(2)) : 0
    }));
  }, [filteredEntries]);

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#6366f1'];

  // --- 6. Export Function ---
  const handleExportReport = () => {
    const csvRows = [];

    csvRows.push(['REPORT SUMMARY']);
    csvRows.push(['Report Type', 'Canteen Analytics (Events Excluded)']);
    csvRows.push(['Period', label]);
    csvRows.push(['Start Date', startDate.toLocaleDateString()]);
    csvRows.push(['End Date', endDate.toLocaleDateString()]);
    csvRows.push([]);

    csvRows.push(['KEY METRICS']);
    csvRows.push(['Total Consumption Cost', consumptionStats.totalCost.toFixed(2)]);
    csvRows.push(['Total Participants', consumptionStats.totalParticipants]);
    csvRows.push(['Avg Cost Per Head', consumptionStats.avgCostPerHead.toFixed(2)]);
    csvRows.push(['Avg Daily Cost', consumptionStats.avgDailyCost.toFixed(2)]);
    csvRows.push(['Total Purchase Est.', purchaseStats.totalPurchaseEst.toFixed(2)]);
    csvRows.push([]);

    csvRows.push(['VENDOR / SUPPLIER ANALYSIS']);
    csvRows.push(['Supplier Name', 'Total Purchase Amount (Est.)']);
    purchaseStats.vendorData.forEach(v => {
        csvRows.push([`"${v.name.replace(/"/g, '""')}"`, v.value.toFixed(2)]);
    });
    csvRows.push([]);

    csvRows.push(['DAILY CONSUMPTION BREAKDOWN']);
    csvRows.push(['Date', 'Participants', 'Total Cost', 'Cost Per Head', 'Menu']);
    filteredEntries.forEach(e => {
        const ph = e.participantCount ? (e.totalCost / e.participantCount).toFixed(2) : "0.00";
        csvRows.push([
            e.date,
            e.participantCount,
            e.totalCost.toFixed(2),
            ph,
            `"${(e.menuDescription || '').replace(/"/g, '""')}"`
        ]);
    });

    const csvContent = csvRows.map(e => e.join(',')).join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `ACI_Canteen_Report_${timeFrame}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-12">
        {/* Header & Controls */}
        <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4 border-b border-slate-200 dark:border-slate-700 pb-6">
            <div>
                <h2 className="text-3xl font-bold text-slate-900 dark:text-white flex items-center gap-3">
                    <PieIcon className="text-blue-600 dark:text-blue-400" size={32} />
                    Analytics & Reporting
                </h2>
                <p className="text-slate-500 dark:text-slate-400 mt-2 font-medium">
                    Generate comprehensive reports on costs, consumption, and supplier performance.
                </p>
            </div>

            <div className="flex flex-col sm:flex-row items-end sm:items-center gap-3 w-full xl:w-auto">
                {timeFrame === 'custom' && (
                    <div className="flex items-center gap-2 bg-white dark:bg-slate-800 p-1 rounded-lg border border-slate-300 dark:border-slate-600">
                        <input 
                            type="date" 
                            value={customStartDate}
                            onChange={(e) => setCustomStartDate(e.target.value)}
                            className="bg-transparent text-sm p-1 outline-none text-slate-700 dark:text-slate-200"
                        />
                        <span className="text-slate-400">-</span>
                        <input 
                            type="date" 
                            value={customEndDate}
                            onChange={(e) => setCustomEndDate(e.target.value)}
                            className="bg-transparent text-sm p-1 outline-none text-slate-700 dark:text-slate-200"
                        />
                    </div>
                )}

                <div className="flex items-center bg-slate-100 dark:bg-slate-800 p-1 rounded-lg border border-slate-200 dark:border-slate-700">
                    <button 
                        onClick={() => { setTimeFrame('week'); setExpandedVendor(null); }}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'week' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Week
                    </button>
                    <button 
                        onClick={() => { setTimeFrame('month'); setExpandedVendor(null); }}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'month' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Month
                    </button>
                    <button 
                        onClick={() => { setTimeFrame('quarter'); setExpandedVendor(null); }}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'quarter' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Quarter
                    </button>
                    <button 
                        onClick={() => { setTimeFrame('year'); setExpandedVendor(null); }}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'year' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Year
                    </button>
                    <button 
                        onClick={() => { setTimeFrame('custom'); setExpandedVendor(null); }}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'custom' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Custom
                    </button>
                </div>

                <button 
                    onClick={handleExportReport}
                    className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-blue-700 shadow-lg shadow-blue-200 dark:shadow-blue-900/50 transition-colors"
                >
                    <Download size={18} /> Export Report
                </button>
            </div>
        </div>

        {/* Date Context Bar */}
        <div className="bg-blue-50 dark:bg-blue-900/20 px-4 py-2 rounded-lg border border-blue-100 dark:border-blue-800 flex items-center gap-2 text-blue-700 dark:text-blue-300 text-sm font-medium">
            <Calendar size={16} />
            Showing data for: <span className="font-bold">{startDate.toLocaleDateString()} - {endDate.toLocaleDateString()}</span>
        </div>

        {/* --- KPI CARDS --- */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-start">
                    <div>
                        <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Total Consumption</p>
                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                            ৳{consumptionStats.totalCost.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                        </h3>
                    </div>
                    <div className="p-3 bg-blue-50 dark:bg-blue-900/30 rounded-xl text-blue-600 dark:text-blue-400">
                        <DollarSign size={20} />
                    </div>
                </div>
                <div className="mt-3 text-xs text-slate-400">
                    Operational expense for selected period
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-start">
                    <div>
                        <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Total Participants</p>
                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                            {consumptionStats.totalParticipants.toLocaleString()}
                        </h3>
                    </div>
                    <div className="p-3 bg-violet-50 dark:bg-violet-900/30 rounded-xl text-violet-600 dark:text-violet-400">
                        <Users size={20} />
                    </div>
                </div>
                <div className="mt-3 text-xs text-slate-400">
                    Avg. {consumptionStats.avgDailyParticipants} per day
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-start">
                    <div>
                        <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Avg Cost Per Head</p>
                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                            ৳{consumptionStats.avgCostPerHead.toFixed(2)}
                        </h3>
                    </div>
                    <div className="p-3 bg-emerald-50 dark:bg-emerald-900/30 rounded-xl text-emerald-600 dark:text-emerald-400">
                        <TrendingUp size={20} />
                    </div>
                </div>
                <div className="mt-3 text-xs text-slate-400">
                    Global average for period
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-start">
                    <div>
                        <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Purchase Est.</p>
                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                            ৳{purchaseStats.totalPurchaseEst.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                        </h3>
                    </div>
                    <div className="p-3 bg-amber-50 dark:bg-amber-900/30 rounded-xl text-amber-600 dark:text-amber-400">
                        <ShoppingBag size={20} />
                    </div>
                </div>
                 <div className="mt-3 text-xs text-slate-400">
                    Stock added value (Vendor purchases)
                </div>
            </div>
        </div>

        {/* --- CHARTS SECTION --- */}
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">

            <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 xl:col-span-2">
                <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-6">Cost Per Head Trend</h3>
                <div className="h-[300px] w-full">
                    {dailyTrendData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                            <LineChart data={dailyTrendData} margin={{ top: 5, right: 20, left: 0, bottom: 0 }}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" opacity={0.5} />
                                <XAxis 
                                    dataKey="date" 
                                    tick={{fontSize: 11, fill: '#64748b'}} 
                                    tickLine={false} 
                                    axisLine={false}
                                    dy={10}
                                />
                                <YAxis 
                                    tick={{fontSize: 11, fill: '#64748b'}} 
                                    tickFormatter={(val) => `৳${val}`} 
                                    tickLine={false} 
                                    axisLine={false}
                                    domain={['auto', 'auto']}
                                />
                                <Tooltip 
                                    cursor={{stroke: '#64748b', strokeWidth: 1, strokeDasharray: '3 3'}}
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                />
                                <Legend wrapperStyle={{fontSize: '12px', marginTop: '10px'}} />
                                <Line 
                                    type="monotone" 
                                    dataKey="PerHead" 
                                    stroke="#10b981" 
                                    strokeWidth={3}
                                    dot={{r: 4, strokeWidth: 2}}
                                    activeDot={{r: 6}}
                                    name="Cost Per Head" 
                                />
                            </LineChart>
                        </ResponsiveContainer>
                    ) : (
                         <div className="h-full flex items-center justify-center text-slate-400 text-sm">No data for selected period</div>
                    )}
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700">
                <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-6">Daily Total Cost</h3>
                <div className="h-[300px] w-full">
                    {dailyTrendData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={dailyTrendData} margin={{ top: 5, right: 0, left: 0, bottom: 0 }}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" opacity={0.5} />
                                <XAxis 
                                    dataKey="date" 
                                    tick={{fontSize: 11, fill: '#64748b'}} 
                                    tickLine={false} 
                                    axisLine={false}
                                />
                                <YAxis 
                                    tick={{fontSize: 11, fill: '#64748b'}} 
                                    tickFormatter={(val) => `৳${(val/1000).toFixed(0)}k`} 
                                    tickLine={false} 
                                    axisLine={false}
                                />
                                <Tooltip 
                                    cursor={{fill: '#f1f5f9', opacity: 0.5}}
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                />
                                <Legend wrapperStyle={{fontSize: '12px', marginTop: '10px'}} />
                                <Bar dataKey="Cost" fill="#3b82f6" name="Total Cost" radius={[4, 4, 0, 0]} maxBarSize={40} />
                            </BarChart>
                        </ResponsiveContainer>
                    ) : (
                         <div className="h-full flex items-center justify-center text-slate-400 text-sm">No data for selected period</div>
                    )}
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 flex flex-col">
                <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-2">Cost by Vendor</h3>
                <p className="text-xs text-slate-500 mb-6">Distribution of procurement costs among top suppliers</p>

                <div className="flex-1 min-h-[300px] flex flex-col md:flex-row items-center gap-6">
                     {purchaseStats.vendorData.length > 0 ? (
                        <>
                             <div className="w-full md:w-1/2 h-[250px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie
                                            data={purchaseStats.vendorData}
                                            cx="50%"
                                            cy="50%"
                                            innerRadius={60}
                                            outerRadius={80}
                                            paddingAngle={2}
                                            dataKey="value"
                                        >
                                            {purchaseStats.vendorData.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="none" />
                                            ))}
                                        </Pie>
                                        <Tooltip formatter={(value: number) => `৳${value.toLocaleString()}`} />
                                    </PieChart>
                                </ResponsiveContainer>
                             </div>

                             <div className="w-full md:w-1/2 h-[250px] overflow-y-auto custom-scrollbar pr-2 space-y-3">
                                 {purchaseStats.vendorData.map((v, idx) => (
                                     <div key={v.name} className="flex justify-between items-center text-sm">
                                         <div className="flex items-center gap-2">
                                             <span className="w-3 h-3 rounded-full shrink-0" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></span>
                                             <button 
                                              onClick={() => setExpandedVendor(v.name)}
                                              className="text-slate-700 dark:text-slate-300 truncate max-w-[120px] hover:text-blue-600 hover:underline text-left transition-all" 
                                              title={v.name}
                                             >
                                               {v.name}
                                             </button>
                                         </div>
                                         <span className="font-bold text-slate-900 dark:text-white">৳{v.value.toLocaleString(undefined, {maximumFractionDigits: 0})}</span>
                                     </div>
                                 ))}
                             </div>
                        </>
                     ) : (
                        <div className="w-full h-full flex items-center justify-center text-slate-400 text-sm">No purchase data found</div>
                     )}
                </div>
            </div>
        </div>

        {/* --- VENDOR TABLE WITH DRILL DOWN --- */}
        <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 overflow-hidden transition-all duration-300">
             <div className="p-6 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center bg-slate-50/50 dark:bg-slate-800/50">
                {expandedVendor ? (
                  <div className="flex items-center gap-4">
                    <button 
                      onClick={() => setExpandedVendor(null)}
                      className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full text-slate-600 dark:text-slate-300 transition-colors"
                      title="Back to Summary"
                    >
                      <ArrowLeft size={20} />
                    </button>
                    <div>
                      <h3 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
                        <FileText size={20} className="text-blue-500" />
                        Purchase Details: {expandedVendor}
                      </h3>
                      <p className="text-xs text-slate-500 dark:text-slate-400">Total period spend: ৳{purchaseStats.vendorData.find(v => v.name === expandedVendor)?.value.toLocaleString()}</p>
                    </div>
                  </div>
                ) : (
                  <h3 className="text-lg font-bold text-slate-800 dark:text-white">Vendor Purchase Summary</h3>
                )}
             </div>

             <div className="overflow-x-auto min-h-[300px]">
                 {expandedVendor ? (
                    <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 dark:bg-slate-700/50 text-slate-500 dark:text-slate-400 uppercase text-xs font-semibold">
                        <tr>
                          <th className="px-6 py-4">Purchase Date</th>
                          <th className="px-6 py-4">Ingredient Item</th>
                          <th className="px-6 py-4 text-center">Quantity</th>
                          <th className="px-6 py-4 text-right">Unit Rate (Est.)</th>
                          <th className="px-6 py-4 text-right">Total Amount (Est.)</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                        {purchaseStats.vendorTxs[expandedVendor]?.map((tx, idx) => (
                          <tr key={tx.id || idx} className="hover:bg-blue-50/30 dark:hover:bg-blue-900/10 transition-colors">
                            <td className="px-6 py-4 whitespace-nowrap">
                              <span className="text-slate-600 dark:text-slate-300 font-medium">
                                {new Date(tx.date).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' })}
                              </span>
                              <span className="block text-[10px] text-slate-400">{new Date(tx.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                            </td>
                            <td className="px-6 py-4">
                              <span className="font-bold text-slate-800 dark:text-slate-100">{tx.itemName}</span>
                            </td>
                            <td className="px-6 py-4 text-center">
                              <span className="px-2 py-1 bg-slate-100 dark:bg-slate-700 rounded-md text-slate-700 dark:text-slate-300 font-bold text-xs">
                                {tx.quantity} {tx.unit}
                              </span>
                            </td>
                            <td className="px-6 py-4 text-right text-slate-500 font-mono">
                              ৳{tx.unitPrice.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                            </td>
                            <td className="px-6 py-4 text-right font-bold text-slate-900 dark:text-white">
                              ৳{tx.total.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                 ) : (
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50 dark:bg-slate-700/50 text-slate-500 dark:text-slate-400 uppercase text-xs font-semibold">
                            <tr>
                                <th className="px-6 py-4">Supplier Name</th>
                                <th className="px-6 py-4 text-right">Total Purchase Amount</th>
                                <th className="px-6 py-4 text-right">% of Total</th>
                                <th className="px-6 py-4 text-center w-24">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                            {purchaseStats.vendorData.length > 0 ? (
                                purchaseStats.vendorData.map((v, idx) => (
                                    <tr key={idx} className="group hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors">
                                        <td className="px-6 py-4">
                                          <button 
                                            onClick={() => setExpandedVendor(v.name)}
                                            className="font-bold text-slate-700 dark:text-slate-200 hover:text-blue-600 dark:hover:text-blue-400 transition-colors flex items-center gap-1"
                                          >
                                            {v.name}
                                            <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 transition-opacity translate-x-0 group-hover:translate-x-1" />
                                          </button>
                                        </td>
                                        <td className="px-6 py-4 text-right font-bold text-slate-900 dark:text-white">
                                          ৳{v.value.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                        </td>
                                        <td className="px-6 py-4 text-right text-slate-500">
                                            {((v.value / purchaseStats.totalPurchaseEst) * 100).toFixed(1)}%
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                          <button 
                                            onClick={() => setExpandedVendor(v.name)}
                                            className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase tracking-wider hover:underline"
                                          >
                                            View Details
                                          </button>
                                        </td>
                                    </tr>
                                ))
                            ) : (
                                <tr>
                                    <td colSpan={4} className="px-6 py-12 text-center text-slate-400 italic">
                                      <div className="flex flex-col items-center gap-2">
                                        <ShoppingBag size={32} className="opacity-20" />
                                        <span>No supplier data for this period.</span>
                                      </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                 )}
             </div>
        </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { TrendingUp, Users, AlertTriangle, ArrowRight, Download, Filter, Calendar, Trash2, AlertCircle, BarChart3, Eye } from 'lucide-react';
import { DailyEntry, Office, Ingredient, UserRole } from '../types';
import { CostSheetDetailsModal } from './CostSheetDetailsModal';

interface DashboardProps {
  title?: string;
  entries: DailyEntry[];
  offices: Office[];
  ingredients: Ingredient[];
  isDarkMode?: boolean;
  userRole: UserRole;
  onDeleteEntry: (id: string) => void;
  onViewMasterStock?: () => void;
  targetPerHead?: number;
}

export const Dashboard: React.FC<DashboardProps> = ({ 
  title = "Executive Dashboard",
  entries, 
  offices, 
  ingredients, 
  isDarkMode, 
  userRole, 
  onDeleteEntry,
  onViewMasterStock,
  targetPerHead = 72.72
}) => {
  const [selectedMonth, setSelectedMonth] = useState<string>('last30');

  // Available years for the Monthly Expenditure Overview
  const availableYears = useMemo(() => {
    const years = new Set(entries.map(e => new Date(e.date).getFullYear()));
    return Array.from(years).sort((a, b) => b - a);
  }, [entries]);

  // Default to the most recent year with data or 2025
  const [selectedYear, setSelectedYear] = useState<number>(() => {
    const years = entries.map(e => new Date(e.date).getFullYear());
    return years.length > 0 ? Math.max(...years) : 2025;
  });

  // State for viewing details modal
  const [selectedEntry, setSelectedEntry] = useState<DailyEntry | null>(null);

  // 1. Available Months for Filter
  const availableMonths = useMemo(() => {
    const months = new Set(entries.map(e => e.date.substring(0, 7))); // YYYY-MM
    return Array.from(months).sort().reverse();
  }, [entries]);

  // 2. Filter Data based on selection (Shared by Chart, KPI, and Table)
  const filteredEntries = useMemo(() => {
    const sortedEntries = [...entries].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    if (selectedMonth === 'last30') {
      // Return last 30 entries
      return sortedEntries.slice(-30);
    }
    // Return entries for the selected month
    return sortedEntries.filter(e => e.date.startsWith(selectedMonth));
  }, [entries, selectedMonth]);

  // 3. Calculate Average Metrics from filtered data
  const { avgDailyCost, avgPerHead, avgParticipants, totalCost } = useMemo(() => {
    if (filteredEntries.length === 0) {
      return { avgDailyCost: 0, avgPerHead: 0, avgParticipants: 0, totalCost: 0 };
    }

    const total = filteredEntries.reduce((sum, e) => sum + e.totalCost, 0);
    const totalParts = filteredEntries.reduce((sum, e) => sum + e.participantCount, 0);

    return {
      avgDailyCost: total / filteredEntries.length,
      avgPerHead: totalParts > 0 ? total / totalParts : 0, // Weighted Average
      avgParticipants: Math.round(totalParts / filteredEntries.length),
      totalCost: total
    };
  }, [filteredEntries]);

  // Check if average per head exceeds target
  const isAvgPerHeadHigh = avgPerHead > targetPerHead;

  // 4. Prepare Chart Data (using filteredEntries)
  const trendData = useMemo(() => {
    return filteredEntries.map((e) => {
      const perHead = e.participantCount > 0 ? e.totalCost / e.participantCount : 0;
      return {
        date: e.date.substring(5), // MM-DD
        CostPerHead: Number(perHead.toFixed(2)),
        TotalCost: e.totalCost
      };
    });
  }, [filteredEntries]);

  // 5. Monthly Aggregation Data (Yearly View)
  const monthlyCostData = useMemo(() => {
    const monthlyTotals: Record<number, number> = {};

    entries.forEach(entry => {
      const date = new Date(entry.date);
      if (date.getFullYear() === selectedYear) {
        const monthIndex = date.getMonth(); // 0-11
        monthlyTotals[monthIndex] = (monthlyTotals[monthIndex] || 0) + entry.totalCost;
      }
    });

    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

    return monthNames.map((name, index) => ({
      name,
      total: monthlyTotals[index] || 0
    })).filter(item => item.total > 0); // Only show months with data
  }, [entries, selectedYear]);

  // 6. Stock Alerts
  const lowStockItems = ingredients.filter(i => i.currentStock <= i.minStockThreshold);

  // 7. Displayed Entries for Table (Descending Order)
  const displayedEntries = useMemo(() => {
    return [...filteredEntries].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredEntries]);

  const handleExportCSV = () => {
    if (displayedEntries.length === 0) {
      alert("No data available to export.");
      return;
    }

    // CSV Headers
    const headers = ["Date", "Participants", "Total Cost", "Per Head Cost", "Menu Description"];

    // Generate CSV Rows
    const csvRows = displayedEntries.map(entry => {
      const perHead = entry.participantCount > 0 ? (entry.totalCost / entry.participantCount).toFixed(2) : "0.00";
      // Escape quotes in menu description and wrap in quotes
      const menu = entry.menuDescription ? `"${entry.menuDescription.replace(/"/g, '""')}"` : '""';

      return [
        entry.date,
        entry.participantCount,
        entry.totalCost.toFixed(2),
        perHead,
        menu
      ].join(",");
    });

    // Combine headers and rows
    const csvString = [headers.join(","), ...csvRows].join("\n");

    // Create Blob and trigger download
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `report_${selectedMonth === 'last30' ? 'last30days' : selectedMonth}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const formatMonth = (monthStr: string) => {
    const [year, month] = monthStr.split('-');
    const date = new Date(parseInt(year), parseInt(month) - 1);
    return date.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
  };

  const handleDeleteClick = (id: string, date: string) => {
    if (window.confirm(`Are you sure you want to delete the entry for ${date}? This action cannot be undone.`)) {
      onDeleteEntry(id);
    }
  };

  const periodLabel = selectedMonth === 'last30' ? 'Last 30 Days' : formatMonth(selectedMonth);

  // Contextual KPI logic
  const isEventReport = title === "Events Cost Report";

  return (
    <div className="space-y-6 md:space-y-8 animate-fade-in pb-10">

      {/* Detail Modal */}
      {selectedEntry && (
        <CostSheetDetailsModal 
          entry={selectedEntry} 
          ingredients={ingredients} 
          onClose={() => setSelectedEntry(null)} 
        />
      )}

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white tracking-tight">{title}</h2>
          <p className="text-sm md:text-base text-slate-500 dark:text-slate-400 mt-1 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
            Overview for {periodLabel}
          </p>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        <div className="bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all group">
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-emerald-50 dark:bg-emerald-900/30 rounded-xl text-emerald-600 dark:text-emerald-400 group-hover:bg-emerald-100 dark:group-hover:bg-emerald-900/50 transition-colors">
              <span className="font-bold text-xl">৳</span>
            </div>
            <span className="text-xs font-semibold text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-900/30 px-2 py-1 rounded-md">
              {isEventReport ? 'Total' : '~ Avg'}
            </span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">
              {isEventReport ? 'Total Cost' : 'Average Daily Cost'}
            </p>
            <h3 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white mt-1">
              ৳{(isEventReport ? totalCost : avgDailyCost).toLocaleString(undefined, { maximumFractionDigits: 0 })}
            </h3>
          </div>
        </div>

        {/* Average Per Head Cost Card */}
        <div className={`bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border hover:shadow-lg transition-all group relative overflow-hidden ${isAvgPerHeadHigh ? 'border-red-200 dark:border-red-900' : 'border-slate-200 dark:border-slate-700'}`}>
          {isAvgPerHeadHigh && (
             <div className="absolute top-0 right-0 w-2 h-2 rounded-full bg-red-500 m-4 animate-ping"></div>
          )}
          <div className="flex justify-between items-start mb-4">
            <div className={`p-3 rounded-xl transition-colors ${isAvgPerHeadHigh ? 'bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400' : 'bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 group-hover:bg-blue-100 dark:group-hover:bg-blue-900/50'}`}>
              <TrendingUp size={24} />
            </div>
             <span className="text-xs font-semibold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded-md">Target: ৳{targetPerHead}</span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Average Per Head Cost</p>
            <h3 className={`text-2xl md:text-3xl font-bold mt-1 ${isAvgPerHeadHigh ? 'text-red-600 dark:text-red-400' : 'text-slate-900 dark:text-white'}`}>
              ৳{avgPerHead.toFixed(2)}
            </h3>
            {isAvgPerHeadHigh && (
              <div className="mt-2 flex items-center gap-1.5 text-xs text-red-600 dark:text-red-400 font-medium">
                <AlertCircle size={12} />
                Exceeds Target by ৳{(avgPerHead - targetPerHead).toFixed(2)}
              </div>
            )}
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all group">
           <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-violet-50 dark:bg-violet-900/30 rounded-xl text-violet-600 dark:text-violet-400 group-hover:bg-violet-100 dark:group-hover:bg-violet-900/50 transition-colors">
              <Users size={24} />
            </div>
            <span className="text-xs font-semibold text-violet-600 dark:text-violet-400 bg-violet-50 dark:bg-violet-900/30 px-2 py-1 rounded-md">
              {isEventReport ? 'Total' : '~ Avg'}
            </span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">
              {isEventReport ? 'Total Participants' : 'Average Participants'}
            </p>
            <h3 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white mt-1">
              {(isEventReport ? filteredEntries.reduce((s, e) => s + e.participantCount, 0) : avgParticipants).toLocaleString()}
            </h3>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all group relative overflow-hidden">
          {lowStockItems.length > 0 && (
             <div className="absolute top-0 right-0 w-2 h-2 rounded-full bg-red-500 m-4 animate-ping"></div>
          )}
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-rose-50 dark:bg-rose-900/30 rounded-xl text-rose-600 dark:text-rose-400 group-hover:bg-rose-100 dark:group-hover:bg-rose-900/50 transition-colors">
              <AlertTriangle size={24} />
            </div>
             <span className={`text-xs font-semibold px-2 py-1 rounded-md ${lowStockItems.length > 0 ? 'text-rose-600 bg-rose-50 dark:text-rose-400 dark:bg-rose-900/30' : 'text-green-600 bg-green-50 dark:text-green-400 dark:bg-green-900/30'}`}>
               {lowStockItems.length > 0 ? 'Action Needed' : 'Healthy'}
             </span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Stock Alerts</p>
            <h3 className={`text-2xl md:text-3xl font-bold mt-1 ${lowStockItems.length > 0 ? 'text-rose-600 dark:text-rose-400' : 'text-slate-900 dark:text-white'}`}>{lowStockItems.length}</h3>
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">

        {/* Cost Per Head Analysis Chart */}
        <div className="xl:col-span-2 bg-white dark:bg-slate-800 p-5 md:p-8 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 flex-wrap gap-4">
            <div>
              <h3 className="text-lg md:text-xl font-bold text-slate-900 dark:text-white">Cost Per Head Analysis</h3>
              <p className="text-xs md:text-sm text-slate-500 dark:text-slate-400">
                {selectedMonth === 'last30' ? '30-day performance trend' : `Analysis for ${formatMonth(selectedMonth)}`}
              </p>
            </div>

            {/* Filter Dropdown */}
            <div className="relative w-full md:w-auto">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Calendar size={16} className="text-slate-500 dark:text-slate-400" />
              </div>
              <select 
                value={selectedMonth}
                onChange={(e) => setSelectedMonth(e.target.value)}
                className="w-full md:w-auto pl-10 pr-8 py-2 bg-slate-50 dark:bg-slate-700 border border-slate-200 dark:border-slate-600 text-slate-700 dark:text-slate-200 text-sm font-medium rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none appearance-none cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-600 transition-colors"
              >
                <option value="last30">Last 30 Days</option>
                {availableMonths.map(month => (
                  <option key={month} value={month}>{formatMonth(month)}</option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                <Filter size={14} className="text-slate-400" />
              </div>
            </div>
          </div>

          <div className="h-[250px] md:h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={trendData} margin={{ top: 10, right: 0, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? "#334155" : "#f1f5f9"} />
                <XAxis 
                  dataKey="date" 
                  stroke={isDarkMode ? "#94a3b8" : "#94a3b8"} 
                  tick={{fontSize: 12}} 
                  tickLine={false}
                  axisLine={false}
                  dy={10}
                />
                <YAxis 
                  stroke={isDarkMode ? "#94a3b8" : "#94a3b8"} 
                  tick={{fontSize: 12}} 
                  tickFormatter={(val) => `৳${val}`} 
                  tickLine={false}
                  axisLine={false}
                />
                <Tooltip 
                  cursor={{fill: isDarkMode ? '#334155' : '#f1f5f9', opacity: 0.4}}
                  contentStyle={{ 
                    backgroundColor: isDarkMode ? '#1e293b' : '#fff', 
                    borderRadius: '12px', 
                    border: isDarkMode ? '1px solid #334155' : 'none',
                    boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1)'
                  }}
                  itemStyle={{ color: isDarkMode ? '#f8fafc' : '#1e293b', fontWeight: 600 }}
                  labelStyle={{ color: '#64748b', marginBottom: '4px' }}
                />
                <Bar 
                  dataKey="CostPerHead" 
                  fill="#3b82f6" 
                  radius={[4, 4, 0, 0]}
                  name="Per Head Cost (৳)"
                  maxBarSize={50}
                />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Stock Alert List */}
        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 flex flex-col">
          <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-6 flex items-center justify-between">
            <span className="flex items-center gap-2">
              Low Stock Warnings
            </span>
            <span className="text-xs font-normal text-slate-400 bg-slate-50 dark:bg-slate-700 px-2 py-1 rounded-full">{lowStockItems.length} Items</span>
          </h3>

          <div className="space-y-4 flex-1 overflow-y-auto pr-2 custom-scrollbar">
            {lowStockItems.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-6 text-slate-400">
                <div className="w-12 h-12 bg-slate-50 dark:bg-slate-700 rounded-full flex items-center justify-center mb-3">
                   <AlertCircle size={20} />
                </div>
                <p className="text-sm">All inventory levels are healthy.</p>
              </div>
            ) : (
              lowStockItems.slice(0, 4).map(item => (
                <div key={item.id} className="group p-4 rounded-xl border border-slate-100 dark:border-slate-700 bg-white dark:bg-slate-800 hover:border-red-100 dark:hover:border-red-900 hover:bg-red-50/30 dark:hover:bg-red-900/10 transition-all">
                  <div className="flex justify-between items-start mb-2">
                    <div>
                      <h4 className="font-semibold text-slate-800 dark:text-slate-200">{item.name}</h4>
                      <p className="text-xs text-slate-500 dark:text-slate-400">Min: {item.minStockThreshold} {item.unit}</p>
                    </div>
                    <span className="text-xs font-bold text-rose-600 dark:text-rose-400 bg-rose-50 dark:bg-rose-900/30 px-2.5 py-1 rounded-full border border-rose-100 dark:border-rose-900">
                      {item.currentStock} {item.unit}
                    </span>
                  </div>
                  <div className="w-full bg-slate-100 dark:bg-slate-700 rounded-full h-1.5 mt-3 overflow-hidden">
                    <div 
                      className="bg-rose-500 h-1.5 rounded-full transition-all duration-500 ease-out" 
                      style={{ width: `${Math.min((item.currentStock / item.minStockThreshold) * 100, 100)}%` }}
                    ></div>
                  </div>
                </div>
              ))
            )}
          </div>

          {lowStockItems.length > 0 && (
             <button 
               onClick={onViewMasterStock}
               className="mt-6 w-full py-2.5 text-sm font-medium text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-600 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 hover:text-slate-900 dark:hover:text-white transition-colors flex items-center justify-center gap-2"
             >
               View in Master Stock <ArrowRight size={14} />
             </button>
          )}
        </div>
      </div>

      {/* Monthly Expenditure Overview (New Chart) */}
      <div className="bg-white dark:bg-slate-800 p-5 md:p-8 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-violet-100 dark:bg-violet-900/30 rounded-lg text-violet-600 dark:text-violet-400">
              <BarChart3 size={20} />
            </div>
            <div>
              <h3 className="text-lg md:text-xl font-bold text-slate-900 dark:text-white">Monthly Expenditure Overview</h3>
              <p className="text-xs md:text-sm text-slate-500 dark:text-slate-400">Total operational cost aggregated by month</p>
            </div>
          </div>

          {/* Year Filter Dropdown */}
          <div className="relative w-full sm:w-auto">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <Calendar size={16} className="text-slate-500 dark:text-slate-400" />
            </div>
            <select 
              value={selectedYear}
              onChange={(e) => setSelectedYear(Number(e.target.value))}
              className="w-full sm:w-auto pl-10 pr-8 py-2 bg-slate-50 dark:bg-slate-700 border border-slate-200 dark:border-slate-600 text-slate-700 dark:text-slate-200 text-sm font-bold rounded-lg focus:ring-2 focus:ring-violet-500 focus:border-violet-500 outline-none appearance-none cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-600 transition-colors"
            >
              {availableYears.map(year => (
                <option key={year} value={year}>{year} Statistics</option>
              ))}
              {availableYears.length === 0 && <option value={new Date().getFullYear()}>{new Date().getFullYear()} Statistics</option>}
            </select>
            <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
              <Filter size={14} className="text-slate-400" />
            </div>
          </div>
        </div>

        <div className="h-[250px] md:h-[300px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={monthlyCostData} margin={{ top: 10, right: 0, left: 0, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? "#334155" : "#f1f5f9"} />
              <XAxis 
                dataKey="name" 
                stroke={isDarkMode ? "#94a3b8" : "#94a3b8"} 
                tick={{fontSize: 12}} 
                tickLine={false}
                axisLine={false}
                dy={10}
              />
              <YAxis 
                stroke={isDarkMode ? "#94a3b8" : "#94a3b8"} 
                tick={{fontSize: 12}} 
                tickFormatter={(val) => `৳${(val/1000).toFixed(0)}k`} 
                tickLine={false}
                axisLine={false}
              />
              <Tooltip 
                cursor={{fill: isDarkMode ? '#334155' : '#f1f5f9', opacity: 0.4}}
                contentStyle={{ 
                  backgroundColor: isDarkMode ? '#1e293b' : '#fff', 
                  borderRadius: '12px', 
                  border: isDarkMode ? '1px solid #334155' : 'none',
                  boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1)'
                }}
                itemStyle={{ color: isDarkMode ? '#f8fafc' : '#1e293b', fontWeight: 600 }}
                formatter={(value: number) => [`৳${value.toLocaleString()}`, 'Total Cost']}
                labelStyle={{ color: '#64748b', marginBottom: '4px' }}
              />
              <Bar 
                dataKey="total" 
                fill="#8b5cf6" 
                radius={[4, 4, 0, 0]}
                name="Total Cost"
                maxBarSize={60}
              />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Daily Costing Table */}
      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 overflow-hidden">
        <div className="p-6 border-b border-slate-100 dark:border-slate-700 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div>
            <h3 className="text-lg md:text-xl font-bold text-slate-900 dark:text-white">Daily Costing Report</h3>
            <p className="text-sm text-slate-500 dark:text-slate-400">
              {selectedMonth === 'last30' ? 'All historical cost sheets (Last 30 Days)' : `Cost sheets for ${formatMonth(selectedMonth)}`}
            </p>
          </div>
          <button 
            onClick={handleExportCSV}
            className="w-full sm:w-auto flex items-center justify-center gap-2 text-sm font-medium text-slate-600 dark:text-slate-300 hover:text-blue-600 dark:hover:text-blue-400 bg-slate-50 dark:bg-slate-700 hover:bg-blue-50 dark:hover:bg-blue-900/30 px-4 py-2 rounded-lg transition-colors"
          >
            <Download size={16} /> Export CSV
          </button>
        </div>

        {/* Desktop Table */}
        <div className="hidden md:block overflow-x-auto">
          <table className="w-full text-sm text-left min-w-[800px]">
            <thead className="text-xs text-slate-500 dark:text-slate-400 uppercase bg-slate-50/50 dark:bg-slate-700/50">
              <tr>
                <th className="px-6 py-4 font-semibold">Date</th>
                <th className="px-6 py-4 font-semibold text-center">Participants</th>
                <th className="px-6 py-4 font-semibold text-right">Total Cost</th>
                <th className="px-6 py-4 font-semibold text-right">Per Head</th>
                <th className="px-6 py-4 font-semibold text-left">Menu</th>
                <th className="px-6 py-4 font-semibold text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
              {displayedEntries.length === 0 ? (
                 <tr>
                 <td colSpan={6} className="px-6 py-12 text-center text-slate-400">
                   No data available for this period.
                 </td>
               </tr>
              ) : (
                displayedEntries.map((entry, idx) => {
                  const perHead = entry.participantCount > 0 ? entry.totalCost / entry.participantCount : 0;
                  const isHighCost = perHead > targetPerHead; // Use dynamic target here too

                  return (
                  <tr key={idx} className="hover:bg-slate-50/80 dark:hover:bg-slate-700/50 transition-colors group">
                    <td className="px-6 py-4 font-medium text-slate-600 dark:text-slate-300 whitespace-nowrap">
                        {entry.date}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className="inline-block px-2 py-1 bg-slate-100 dark:bg-slate-700 rounded text-slate-700 dark:text-slate-300 font-medium text-xs">
                        {entry.participantCount}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right text-slate-600 dark:text-slate-300">
                      ৳{entry.totalCost.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}
                    </td>
                    <td className="px-6 py-4 text-right">
                       <div className={`inline-flex items-center justify-end gap-1.5 ${isHighCost ? 'text-rose-600 dark:text-rose-400 bg-rose-50 dark:bg-rose-900/30 px-2 py-1 rounded-md border border-rose-100 dark:border-rose-900' : 'text-slate-900 dark:text-white'}`} title={isHighCost ? `Exceeds ৳${targetPerHead} target` : ""}>
                         {isHighCost && <AlertCircle size={14} className="shrink-0" />}
                         <span className="font-semibold">
                           ৳{perHead.toFixed(2)}
                         </span>
                       </div>
                    </td>
                    <td className="px-6 py-4 text-left">
                      <span className="text-slate-700 dark:text-slate-300 text-xs font-medium bg-blue-50/50 dark:bg-blue-900/20 px-3 py-1.5 rounded-md border border-blue-50 dark:border-blue-900/30 inline-block max-w-xs truncate" title={entry.menuDescription}>
                        {entry.menuDescription || "Standard Menu"}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <div className="flex items-center justify-center gap-2">
                        <button 
                          onClick={() => setSelectedEntry(entry)}
                          className="text-slate-400 hover:text-blue-500 transition-colors p-2 rounded-full hover:bg-blue-50 dark:hover:bg-blue-900/20"
                          title="View Details"
                        >
                          <Eye size={16} />
                        </button>
                        {userRole === 'ADMIN' && (
                          <button 
                            onClick={() => handleDeleteClick(entry.id, entry.date)}
                            className="text-slate-400 hover:text-red-500 transition-colors p-2 rounded-full hover:bg-red-50 dark:hover:bg-red-900/20"
                            title="Delete Entry"
                          >
                            <Trash2 size={16} />
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>

        {/* Mobile List View */}
        <div className="md:hidden space-y-4 p-4 bg-slate-50 dark:bg-slate-900/50">
           {displayedEntries.length === 0 ? (
             <div className="text-center py-10 text-slate-400">
               No data available for this period.
             </div>
           ) : (
             displayedEntries.map((entry, idx) => {
               const perHead = entry.participantCount > 0 ? entry.totalCost / entry.participantCount : 0;
               const isHighCost = perHead > targetPerHead;

               return (
                 <div key={idx} className="bg-white dark:bg-slate-800 rounded-xl p-4 shadow-sm border border-slate-200 dark:border-slate-700">
                    <div className="flex justify-between items-start mb-3">
                       <div>
                          <p className="font-bold text-slate-800 dark:text-white text-lg">{entry.date}</p>
                          <span className="inline-block mt-1 px-2 py-0.5 bg-slate-100 dark:bg-slate-700 rounded text-slate-500 dark:text-slate-400 font-bold text-xs">
                             {entry.participantCount} Participants
                          </span>
                       </div>
                       <div className="flex gap-2">
                           <button 
                            onClick={() => setSelectedEntry(entry)}
                            className="p-2 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded-lg"
                          >
                            <Eye size={18} />
                          </button>
                          {userRole === 'ADMIN' && (
                            <button 
                              onClick={() => handleDeleteClick(entry.id, entry.date)}
                              className="p-2 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-lg"
                            >
                              <Trash2 size={18} />
                            </button>
                          )}
                       </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4 mb-3">
                       <div className="p-3 bg-slate-50 dark:bg-slate-700/30 rounded-lg">
                          <p className="text-xs text-slate-500 dark:text-slate-400 font-bold uppercase">Total Cost</p>
                          <p className="text-lg font-bold text-slate-800 dark:text-white">৳{entry.totalCost.toLocaleString(undefined, {maximumFractionDigits: 0})}</p>
                       </div>
                       <div className={`p-3 rounded-lg ${isHighCost ? 'bg-red-50 dark:bg-red-900/20' : 'bg-slate-50 dark:bg-slate-700/30'}`}>
                          <div className="flex items-center gap-1">
                             <p className={`text-xs font-bold uppercase ${isHighCost ? 'text-red-600 dark:text-red-400' : 'text-slate-500 dark:text-slate-400'}`}>Per Head</p>
                             {isHighCost && <AlertCircle size={12} className="text-red-500" />}
                          </div>
                          <p className={`text-lg font-bold ${isHighCost ? 'text-red-700 dark:text-red-300' : 'text-slate-800 dark:text-white'}`}>৳{perHead.toFixed(2)}</p>
                       </div>
                    </div>

                    <div>
                       <p className="text-xs font-bold text-slate-400 uppercase mb-1">Menu</p>
                       <p className="text-sm text-slate-600 dark:text-slate-300 line-clamp-2">
                          {entry.menuDescription || "Standard Menu"}
                       </p>
                    </div>
                 </div>
               );
             })
           )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { TrendingUp, Users, AlertTriangle, ArrowRight, Download, Filter, Calendar, Trash2, AlertCircle, BarChart3, Eye } from 'lucide-react';
import { DailyEntry, Office, Ingredient, UserRole } from '../types';
import { CostSheetDetailsModal } from './CostSheetDetailsModal';

interface DashboardProps {
  title?: string;
  entries: DailyEntry[];
  offices: Office[];
  ingredients: Ingredient[];
  isDarkMode?: boolean;
  userRole: UserRole;
  onDeleteEntry: (id: string) => void;
  onViewMasterStock?: () => void;
  targetPerHead?: number;
}

export const Dashboard: React.FC<DashboardProps> = ({ 
  title = "Executive Dashboard",
  entries, 
  offices, 
  ingredients, 
  isDarkMode, 
  userRole, 
  onDeleteEntry,
  onViewMasterStock,
  targetPerHead = 72.72
}) => {
  const [selectedMonth, setSelectedMonth] = useState<string>('last30');

  // Available years for the Monthly Expenditure Overview
  const availableYears = useMemo(() => {
    const years = new Set(entries.map(e => new Date(e.date).getFullYear()));
    // Fix: Explicitly type parameters to avoid arithmetic operation errors
    return Array.from(years).sort((a: number, b: number) => b - a);
  }, [entries]);

  // Default to the most recent year with data or 2025
  const [selectedYear, setSelectedYear] = useState<number>(() => {
    const years = entries.map(e => new Date(e.date).getFullYear());
    return years.length > 0 ? Math.max(...years) : 2025;
  });

  // State for viewing details modal
  const [selectedEntry, setSelectedEntry] = useState<DailyEntry | null>(null);

  // 1. Available Months for Filter
  const availableMonths = useMemo(() => {
    const months = new Set(entries.map(e => e.date.substring(0, 7))); // YYYY-MM
    return Array.from(months).sort().reverse();
  }, [entries]);

  // 2. Filter Data based on selection (Shared by Chart, KPI, and Table)
  const filteredEntries = useMemo(() => {
    const sortedEntries = [...entries].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    if (selectedMonth === 'last30') {
      // Return last 30 entries
      return sortedEntries.slice(-30);
    }
    // Return entries for the selected month
    return sortedEntries.filter(e => e.date.startsWith(selectedMonth));
  }, [entries, selectedMonth]);

  // 3. Calculate Average Metrics from filtered data
  const { avgDailyCost, avgPerHead, avgParticipants, totalCost } = useMemo(() => {
    if (filteredEntries.length === 0) {
      return { avgDailyCost: 0, avgPerHead: 0, avgParticipants: 0, totalCost: 0 };
    }

    const total = filteredEntries.reduce((sum, e) => sum + e.totalCost, 0);
    const totalParts = filteredEntries.reduce((sum, e) => sum + e.participantCount, 0);

    return {
      avgDailyCost: total / filteredEntries.length,
      avgPerHead: totalParts > 0 ? total / totalParts : 0, // Weighted Average
      avgParticipants: Math.round(totalParts / filteredEntries.length),
      totalCost: total
    };
  }, [filteredEntries]);

  // Check if average per head exceeds target
  const isAvgPerHeadHigh = avgPerHead > targetPerHead;

  // 4. Prepare Chart Data (using filteredEntries)
  const trendData = useMemo(() => {
    return filteredEntries.map((e) => {
      const perHead = e.participantCount > 0 ? e.totalCost / e.participantCount : 0;
      return {
        date: e.date.substring(5), // MM-DD
        CostPerHead: Number(perHead.toFixed(2)),
        TotalCost: e.totalCost
      };
    });
  }, [filteredEntries]);

  // 5. Monthly Aggregation Data (Yearly View)
  const monthlyCostData = useMemo(() => {
    const monthlyTotals: Record<number, number> = {};

    entries.forEach(entry => {
      const date = new Date(entry.date);
      if (date.getFullYear() === selectedYear) {
        const monthIndex = date.getMonth(); // 0-11
        monthlyTotals[monthIndex] = (monthlyTotals[monthIndex] || 0) + entry.totalCost;
      }
    });

    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

    return monthNames.map((name, index) => ({
      name,
      total: monthlyTotals[index] || 0
    })).filter(item => item.total > 0); // Only show months with data
  }, [entries, selectedYear]);

  // 6. Stock Alerts
  const lowStockItems = ingredients.filter(i => i.currentStock <= i.minStockThreshold);

  // 7. Displayed Entries for Table (Descending Order)
  const displayedEntries = useMemo(() => {
    return [...filteredEntries].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredEntries]);

  const handleExportCSV = () => {
    if (displayedEntries.length === 0) {
      alert("No data available to export.");
      return;
    }

    // CSV Headers
    const headers = ["Date", "Participants", "Total Cost", "Per Head Cost", "Menu Description"];

    // Generate CSV Rows
    const csvRows = displayedEntries.map(entry => {
      const perHead = entry.participantCount > 0 ? (entry.totalCost / entry.participantCount).toFixed(2) : "0.00";
      // Escape quotes in menu description and wrap in quotes
      const menu = entry.menuDescription ? `"${entry.menuDescription.replace(/"/g, '""')}"` : '""';

      return [
        entry.date,
        entry.participantCount,
        entry.totalCost.toFixed(2),
        perHead,
        menu
      ].join(",");
    });

    // Combine headers and rows
    const csvString = [headers.join(","), ...csvRows].join("\n");

    // Create Blob and trigger download
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `report_${selectedMonth === 'last30' ? 'last30days' : selectedMonth}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const formatMonth = (monthStr: string) => {
    const [year, month] = monthStr.split('-');
    const date = new Date(parseInt(year), parseInt(month) - 1);
    return date.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
  };

  const handleDeleteClick = (id: string, date: string) => {
    if (window.confirm(`Are you sure you want to delete the entry for ${date}? This action cannot be undone.`)) {
      onDeleteEntry(id);
    }
  };

  const periodLabel = selectedMonth === 'last30' ? 'Last 30 Days' : formatMonth(selectedMonth);

  // Contextual KPI logic
  const isEventReport = title === "Events Cost Report";

  return (
    <div className="space-y-6 md:space-y-8 animate-fade-in pb-10">

      {/* Detail Modal */}
      {selectedEntry && (
        <CostSheetDetailsModal 
          entry={selectedEntry} 
          ingredients={ingredients} 
          onClose={() => setSelectedEntry(null)} 
        />
      )}

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white tracking-tight">{title}</h2>
          <p className="text-sm md:text-base text-slate-500 dark:text-slate-400 mt-1 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
            Overview for {periodLabel}
          </p>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        <div className="bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all group">
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-emerald-50 dark:bg-emerald-900/30 rounded-xl text-emerald-600 dark:text-emerald-400 group-hover:bg-emerald-100 dark:group-hover:bg-emerald-900/50 transition-colors">
              <span className="font-bold text-xl">৳</span>
            </div>
            <span className="text-xs font-semibold text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-900/30 px-2 py-1 rounded-md">
              {isEventReport ? 'Total' : '~ Avg'}
            </span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">
              {isEventReport ? 'Total Cost' : 'Average Daily Cost'}
            </p>
            <h3 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white mt-1">
              ৳{(isEventReport ? totalCost : avgDailyCost).toLocaleString(undefined, { maximumFractionDigits: 0 })}
            </h3>
          </div>
        </div>

        {/* Average Per Head Cost Card */}
        <div className={`bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border hover:shadow-lg transition-all group relative overflow-hidden ${isAvgPerHeadHigh ? 'border-red-200 dark:border-red-900' : 'border-slate-200 dark:border-slate-700'}`}>
          {isAvgPerHeadHigh && (
             <div className="absolute top-0 right-0 w-2 h-2 rounded-full bg-red-500 m-4 animate-ping"></div>
          )}
          <div className="flex justify-between items-start mb-4">
            <div className={`p-3 rounded-xl transition-colors ${isAvgPerHeadHigh ? 'bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400' : 'bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 group-hover:bg-blue-100 dark:group-hover:bg-blue-900/50'}`}>
              <TrendingUp size={24} />
            </div>
             <span className="text-xs font-semibold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded-md">Target: ৳{targetPerHead}</span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Average Per Head Cost</p>
            <h3 className={`text-2xl md:text-3xl font-bold mt-1 ${isAvgPerHeadHigh ? 'text-red-600 dark:text-red-400' : 'text-slate-900 dark:text-white'}`}>
              ৳{avgPerHead.toFixed(2)}
            </h3>
            {isAvgPerHeadHigh && (
              <div className="mt-2 flex items-center gap-1.5 text-xs text-red-600 dark:text-red-400 font-medium">
                <AlertCircle size={12} />
                Exceeds Target by ৳{(avgPerHead - targetPerHead).toFixed(2)}
              </div>
            )}
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all group">
           <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-violet-50 dark:bg-violet-900/30 rounded-xl text-violet-600 dark:text-violet-400 group-hover:bg-violet-100 dark:group-hover:bg-violet-900/50 transition-colors">
              <Users size={24} />
            </div>
            <span className="text-xs font-semibold text-violet-600 dark:text-violet-400 bg-violet-50 dark:bg-violet-900/30 px-2 py-1 rounded-md">
              {isEventReport ? 'Total' : '~ Avg'}
            </span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">
              {isEventReport ? 'Total Participants' : 'Average Participants'}
            </p>
            <h3 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white mt-1">
              {(isEventReport ? filteredEntries.reduce((s, e) => s + e.participantCount, 0) : avgParticipants).toLocaleString()}
            </h3>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all group relative overflow-hidden">
          {lowStockItems.length > 0 && (
             <div className="absolute top-0 right-0 w-2 h-2 rounded-full bg-red-500 m-4 animate-ping"></div>
          )}
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-rose-50 dark:bg-rose-900/30 rounded-xl text-rose-600 dark:text-rose-400 group-hover:bg-rose-100 dark:group-hover:bg-rose-900/50 transition-colors">
              <AlertTriangle size={24} />
            </div>
             <span className={`text-xs font-semibold px-2 py-1 rounded-md ${lowStockItems.length > 0 ? 'text-rose-600 bg-rose-50 dark:text-rose-400 dark:bg-rose-900/30' : 'text-green-600 bg-green-50 dark:text-green-400 dark:bg-green-900/30'}`}>
               {lowStockItems.length > 0 ? 'Action Needed' : 'Healthy'}
             </span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Stock Alerts</p>
            <h3 className={`text-2xl md:text-3xl font-bold mt-1 ${lowStockItems.length > 0 ? 'text-rose-600 dark:text-rose-400' : 'text-slate-900 dark:text-white'}`}>{lowStockItems.length}</h3>
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">

        {/* Cost Per Head Analysis Chart */}
        <div className="xl:col-span-2 bg-white dark:bg-slate-800 p-5 md:p-8 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 flex-wrap gap-4">
            <div>
              <h3 className="text-lg md:text-xl font-bold text-slate-900 dark:text-white">Cost Per Head Analysis</h3>
              <p className="text-xs md:text-sm text-slate-500 dark:text-slate-400">
                {selectedMonth === 'last30' ? '30-day performance trend' : `Analysis for ${formatMonth(selectedMonth)}`}
              </p>
            </div>

